import React, { useState } from "react";
import TestimonialCard from "./TestimonialCard";
import { motion } from "framer-motion";

const cardsData = [
  // ... (tu array de cardsData igual)
];

const PersonalSection = () => {
  const [index, setIndex] = useState(0);

  const visibleCount = 4;
  const lastIndex = cardsData.length - visibleCount;

  const visibleCards = cardsData.slice(index, index + visibleCount);

  const handleNext = () => {
    if (index < lastIndex) setIndex(index + 1);
  };

  const handlePrev = () => {
    if (index > 0) setIndex(index - 1);
  };

  return (
    <section style={{ textAlign: "center", padding: "1rem" }}>
      <h2
        style={{
          fontSize: "2rem",          // más grande
          fontWeight: "700",
          color: "#000000",          // negro
          marginBottom: "2rem",
          userSelect: "none",
        }}
      >
        LAS PERSONAS Y EQUIPOS QUE HICIERON POSIBLE
      </h2>

      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: "0.8rem",
          flexWrap: "nowrap",
          overflow: "hidden",
          maxWidth: "1600px",
          margin: "0 auto",
          padding: "0 0.5rem",
        }}
      >
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handlePrev}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 45,
            height: 45,
            borderRadius: "50%",
            fontSize: "1.7rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
            flexShrink: 0,
            marginRight: 5,
            opacity: index === 0 ? 0.3 : 1,
            pointerEvents: index === 0 ? "none" : "auto",
          }}
          aria-label="Anterior"
        >
          ◀
        </motion.button>

        <div
          style={{
            display: "flex",
            gap: "0.5rem",
            overflow: "hidden",
            flexGrow: 1,
            justifyContent: "center",
          }}
        >
          {visibleCards.map((card, i) => (
            <TestimonialCard key={index + i} card={card} />
          ))}
        </div>

        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleNext}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 45,
            height: 45,
            borderRadius: "50%",
            fontSize: "1.7rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
            flexShrink: 0,
            marginLeft: 5,
            opacity: index === lastIndex ? 0.3 : 1,
            pointerEvents: index === lastIndex ? "none" : "auto",
          }}
          aria-label="Siguiente"
        >
          ▶
        </motion.button>
      </div>
    </section>
  );
};

export default PersonalSection;
